<form action="" id="step4-form">
    <div class="form-group">
        <label for="">
            <h4>Dokumen Identitas Diri</h4>
        </label>
        <div class="alert alert-secondary" role="alert">
            Dokumen Identitas Pribadi harus di bawah <strong>:name</strong>
        </div>
    
        <div class="mt-3">
            <div class="font-weight-bold">Nomor KTP</div>
            <input name="id_card" type="text" class="form-control">
        </div>
    
        <div class="mt-3">
            <div class="font-weight-bold">Foto KTP</div>
            <input name="id_card_file" type="file" class="form-control" accept="image/*">
        </div>
    
        <div class="mt-3">
            <div class="font-weight-bold">Nomor NPWP</div>
            <input name="npwp" type="text" class="form-control">
        </div>
    
        <div class="mt-3">
            <div class="font-weight-bold">Foto NPWP</div>
            <input name="npwp_file" type="file" class="form-control" accept="image/*">
        </div>
    </div>
    
    
    <div class="form-group">
        <label for="">
            <h4>Tanda tangani Service Agreement</h4>
        </label>
        <div class="">
            <button data-toggle="modal" data-target="#exampleModalLong" type="button" class="btn btn-outline-primary">Buka surat persetujuan</button>
        </div>
    </div>

    <div class="form-group">
        <button type="submit" class="btn btn-primary btn-block submit">Kirim permintaan aktivasi</button>
    </div>
</form>

<div class="modal fade" id="exampleModalLong" tabindex="-1" role="dialog" aria-labelledby="exampleModalLongTitle" aria-hidden="true">
    <div class="modal-dialog modal-lg" role="document">
      <div class="modal-content">
        <div class="modal-header">
          <h5 class="modal-title" id="exampleModalLongTitle">Perjanjian layanan</h5>
          {{-- <button type="button" class="close" data-dismiss="modal" aria-label="Close">
            <span aria-hidden="true">&times;</span>
          </button> --}}
        </div>
        <div class="modal-body">
            <h3>Mohon melakukan pemeriksaan dan menerima persyaratan yang terdapat dalam perjanjian layanan</h3>
            <p>Pastikan bahwa Anda telah melakukan verifikasi email Anda karena salinan perjanjian elektronik akan dikirimkan ke email tersebut</p>
            <div class="mt-3 alert alert-secondary border-0" role="alert">
